mapper.select:
select sc.id, sc.nick_name, sc.account, sc.username, sc.followers_num, sc.star, sc.country, sc.platform_type, sc.like_tags, sc.gender, scf.celebrity_id, scf.is_dispose from store_celebrity sc LEFT JOIN store_celebrity_feedback scf ON scf.celebrity_id=sc.id WHERE scf.celebrity_id is not null and scf.is_dispose=0
and sc.nick_name like '%${storeCelebrityFeedbackModel.nickName}%'
and sc.followers_num >= #{storeCelebrityFeedbackModel.followersStartNum}
and sc.followers_num <= #{storeCelebrityFeedbackModel.followersEndNum}
and sc.platform_type = #{storeCelebrityFeedbackModel.platformType}
GROUP BY sc.nick_name, sc.account, sc.username, sc.followers_num, sc.star, sc.country, sc.platform_type, sc.like_tags, sc.gender, scf.celebrity_id, scf.is_dispose
